// ═══════════════════════════════════════════════════════════
// 🧼 SSSanitizer — minimal, dependency-free HTML sanitizer
// ═══════════════════════════════════════════════════════════
//
// WHY (W5 hardening):
//   eBay listing descriptions are intentionally rich HTML that we render as a
//   live preview before the user publishes them. That HTML is assembled from
//   templates + scraped marketplace fields (title, bullet points, specs), which
//   are untrusted. Rendering them straight into innerHTML is a DOM-XSS sink.
//
//   This sanitizer lets us keep the rich-HTML preview while stripping anything
//   executable: <script>/<iframe>/<object>/<embed>/<link>/<meta>/<style>,
//   every on* event-handler attribute, and javascript:/data: URLs.
//
// It uses DOMParser so it never executes the input while parsing. Callers that
// only need plain text should use textContent instead of this.
(function () {
  'use strict';

  const DANGEROUS_TAGS = ['script', 'iframe', 'object', 'embed', 'link', 'meta', 'style', 'base', 'form'];
  const URL_ATTRS = ['href', 'src', 'xlink:href', 'action', 'formaction'];

  function isUnsafeUrl(value) {
    if (!value) return false;
    // Collapse whitespace/control chars that are used to smuggle schemes.
    const v = String(value).replace(/[�- ]+/g, '').toLowerCase();
    return v.startsWith('javascript:') || v.startsWith('data:') || v.startsWith('vbscript:');
  }

  function scrub(root) {
    // Remove dangerous elements entirely.
    root.querySelectorAll(DANGEROUS_TAGS.join(',')).forEach((el) => el.remove());

    // Walk everything else and strip unsafe attributes.
    root.querySelectorAll('*').forEach((el) => {
      for (const attr of Array.from(el.attributes)) {
        const name = attr.name.toLowerCase();
        if (name.startsWith('on')) {
          el.removeAttribute(attr.name); // event handlers
          continue;
        }
        if (URL_ATTRS.includes(name) && isUnsafeUrl(attr.value)) {
          el.removeAttribute(attr.name); // javascript:/data: URLs
          continue;
        }
        if (name === 'style' && /expression\s*\(|url\s*\(\s*['"]?\s*javascript:/i.test(attr.value)) {
          el.removeAttribute(attr.name); // legacy CSS expression() vectors
        }
      }
    });
  }

  function sanitizeHtml(html) {
    if (html == null) return '';
    const input = String(html);
    try {
      if (typeof DOMParser === 'undefined') {
        // No DOM (e.g. service worker): fall back to hard-stripping tags.
        return input
          .replace(/<\s*(script|iframe|object|embed|style|link|meta|base|form)[\s\S]*?>[\s\S]*?<\s*\/\s*\1\s*>/gi, '')
          .replace(/<\s*(script|iframe|object|embed|style|link|meta|base|form)\b[^>]*>/gi, '')
          .replace(/\son\w+\s*=\s*(?:"[^"]*"|'[^']*'|[^\s>]+)/gi, '');
      }
      const doc = new DOMParser().parseFromString(input, 'text/html');
      scrub(doc.body);
      return doc.body.innerHTML;
    } catch (e) {
      // On any failure, prefer safety: return text-escaped content.
      return input.replace(/[<>&"']/g, (c) => ({
        '<': '&lt;', '>': '&gt;', '&': '&amp;', '"': '&quot;', "'": '&#39;'
      }[c]));
    }
  }

  const api = { sanitizeHtml, isUnsafeUrl };

  const g =
    (typeof globalThis !== 'undefined' && globalThis) ||
    (typeof self !== 'undefined' && self) ||
    (typeof window !== 'undefined' && window) ||
    null;
  if (g) g.SSSanitizer = api;

  if (typeof module !== 'undefined' && module.exports) {
    module.exports = api;
  }
})();
